let filtered = [...DATA];
let currentProject = null;

// Init
window.onload = () => {
  const locs = [...new Set(DATA.map(d => d.location))].sort();
  const sel = document.getElementById('locFilter');
  locs.forEach(l => { const o = document.createElement('option'); o.value = l; o.textContent = l; sel.appendChild(o); });

  const devs = new Set(DATA.map(d => d.developer));
  document.getElementById('stat-devs').textContent = devs.size;

  renderGrid(DATA);
};

function filterProjects() {
  const q = document.getElementById('searchInput').value.toLowerCase();
  const loc = document.getElementById('locFilter').value;
  const sort = document.getElementById('sortFilter').value;

  filtered = DATA.filter(p => {
    const matchQ = !q || p.name.toLowerCase().includes(q) || p.developer.toLowerCase().includes(q) || p.rera_no.toLowerCase().includes(q);
    const matchLoc = !loc || p.location === loc;
    return matchQ && matchLoc;
  });

  if (sort === 'recent') filtered.sort((a,b) => b.last_modified.localeCompare(a.last_modified));
  else filtered.sort((a,b) => a.name.localeCompare(b.name));

  document.getElementById('resultsCount').innerHTML = `<strong>${filtered.length}</strong> project${filtered.length !== 1 ? 's' : ''}`;
  renderGrid(filtered);
}

function renderGrid(projects) {
  const grid = document.getElementById('grid');
  const empty = document.getElementById('emptyState');

  if (!projects.length) {
    grid.innerHTML = '';
    empty.style.display = 'block';
    return;
  }
  empty.style.display = 'none';

  grid.innerHTML = projects.map((p, i) => `
    <div class="card" style="animation-delay:${Math.min(i,20)*0.03}s">
      <div class="card-rera">
        ${p.rera_no}
        <a href="${p.detail_url}" target="_blank">View on RERA ↗</a>
      </div>
      <div class="card-name">${p.name}</div>
      <div class="card-dev"><strong>${p.developer}</strong></div>
      <div class="card-meta">
        <span class="tag">
          <svg width="11" height="11" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg>
          ${p.location}
        </span>
        <span class="tag">
          <svg width="11" height="11" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
          Updated ${p.last_modified}
        </span>
      </div>
      <div class="card-footer">
        <a class="btn-view" href="${p.detail_url}" target="_blank">
          <svg width="12" height="12" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>
          RERA Details
        </a>
        <button class="btn-lead" onclick="openEnquiry(${i})">
          <svg width="12" height="12" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A19.5 19.5 0 0 1 4.69 13.8a19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 3.6 3h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 10.9a16 16 0 0 0 5.61 5.61l1.27-.85a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"/></svg>
          Send Enquiry
        </button>
      </div>
    </div>
  `).join('');
}

function openEnquiry(gridIdx) {
  currentProject = filtered[gridIdx];
  document.getElementById('modalProjectInfo').innerHTML = `
    <strong>${currentProject.name}</strong>
    <span>${currentProject.developer} · ${currentProject.location}</span>
  `;
  document.getElementById('modalForm').style.display = 'block';
  document.getElementById('successMsg').style.display = 'none';
  document.getElementById('leadName').value = '';
  document.getElementById('leadPhone').value = '';
  document.getElementById('leadMsg').value = '';
  document.getElementById('modalOverlay').classList.add('open');
}

function openPartnerModal() {
  currentProject = { name: 'Partner Listing', developer: 'New Partner', location: 'Pune' };
  document.getElementById('modalProjectInfo').innerHTML = `
    <strong>List Your Project</strong>
    <span>Get qualified buyer enquiries from verified leads</span>
  `;
  document.getElementById('modalForm').style.display = 'block';
  document.getElementById('successMsg').style.display = 'none';
  document.getElementById('leadName').value = '';
  document.getElementById('leadPhone').value = '';
  document.getElementById('leadMsg').value = '';
  document.getElementById('modalOverlay').classList.add('open');
}

function closeModal() {
  document.getElementById('modalOverlay').classList.remove('open');
}

function closeModalOutside(e) {
  if (e.target === document.getElementById('modalOverlay')) closeModal();
}

function submitLead() {
  const name = document.getElementById('leadName').value.trim();
  const phone = document.getElementById('leadPhone').value.trim();
  if (!name || !phone) { alert('Please enter your name and phone number.'); return; }

  // Log lead (in production this would POST to your backend)
  console.log('LEAD:', { project: currentProject?.rera_no, name, phone, msg: document.getElementById('leadMsg').value, ts: new Date().toISOString() });

  document.getElementById('modalForm').style.display = 'none';
  document.getElementById('successMsg').style.display = 'block';
  setTimeout(closeModal, 2800);
}
